import React, { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { ArrowUpRight } from "lucide-react";

gsap.registerPlugin(ScrollTrigger);

export function Footer() {
  const sectionRef = useRef<HTMLDivElement>(null);
  const labelRef = useRef<HTMLDivElement>(null);
  const headingRef = useRef<HTMLHeadingElement>(null);
  const emailRef = useRef<HTMLDivElement>(null);
  const linksRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const section = sectionRef.current;
    const label = labelRef.current;
    const heading = headingRef.current;
    const email = emailRef.current;
    const links = linksRef.current;

    if (!section || !label || !heading || !email || !links) return;

    const words = heading.querySelectorAll(".word-inner");

    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: section,
        start: "top 85%", // trigger slightly earlier since footers are at the bottom
        once: true,
      },
    });

    // Step 1: Slide up category label
    tl.fromTo(
      label,
      { y: 30, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.8, ease: "power3.out" }
    )
    // Step 2: Stagger reveal of header words
    .fromTo(
      words,
      { y: "110%", rotate: 2 },
      {
        y: "0%",
        rotate: 0,
        duration: 1.0,
        ease: "power4.out",
        stagger: 0.03,
      },
      "-=0.6"
    )
    // Step 3: Slide up the email block
    .fromTo(
      email,
      { y: 30, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.8, ease: "power3.out" },
      "-=0.6"
    )
    // Step 4: Slide up the footer links block
    .fromTo(
      links,
      { y: 30, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.8, ease: "power3.out" },
      "-=0.6"
    );

    return () => {
      if (tl.scrollTrigger) tl.scrollTrigger.kill();
      tl.kill();
    };
  }, []);

  const handleScrollToTop = (e: React.MouseEvent) => {
    e.preventDefault();
    // Scroll smoothly to top
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const headingText = "LET'S ALIGN ON YOUR PROJECT";

  return (
    <footer
      ref={sectionRef}
      className="relative w-full bg-[#070708] text-[#F5F5F7] px-8 md:px-16 pt-32 pb-16 flex flex-col justify-between border-t border-[#1c1c1e]/40 z-30"
      id="contact"
    >
      <div className="max-w-6xl mx-auto w-full flex flex-col gap-24">
        {/* Top Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-24">
          {/* Category Label */}
          <div className="lg:col-span-3">
            <div
              ref={labelRef}
              className="flex items-center gap-3 text-[#E5C158] font-mono text-sm tracking-widest uppercase opacity-0"
            >
              <span className="w-1.5 h-1.5 rounded-full bg-[#E5C158]" />
              <span>03 / Inquiries</span>
            </div>
          </div>

          {/* Heading and Email */}
          <div className="lg:col-span-9 flex flex-col gap-10">
            <h2
              ref={headingRef}
              className="text-4xl md:text-6xl font-primary font-semibold tracking-tight text-left leading-none"
            >
              {headingText.split(" ").map((word, idx) => (
                <span key={idx} className="word-mask mr-[0.25em] py-[0.1em] -my-[0.1em]">
                  <span className="word-inner inline-block transform origin-left">
                    {word}
                  </span>
                </span>
              ))}
            </h2>

            {/* Large Email Portal Link */}
            <div ref={emailRef} className="group relative inline-block self-start opacity-0">
              <a
                href="mailto:hello@lumerlabs.com"
                className="text-3xl md:text-5xl lg:text-6xl font-extralight tracking-tight text-[#8E8E93] group-hover:text-[#E5C158] transition-colors duration-500 flex items-center gap-4 py-2"
                id="email-link"
              >
                <span>hello@lumerlabs.com</span>
                <ArrowUpRight className="w-8 h-8 md:w-12 md:h-12 text-[#8E8E93]/40 group-hover:text-[#E5C158] group-hover:translate-x-2 group-hover:-translate-y-2 transition-all duration-500" />
              </a>
              {/* Expanding Underline */}
              <div className="h-[1px] w-full bg-[#1c1c1e] group-hover:bg-[#E5C158]/50 transition-colors duration-500 mt-2 relative overflow-hidden">
                <div className="absolute inset-0 bg-[#E5C158] -translate-x-full group-hover:translate-x-0 transition-transform duration-500 ease-out" />
              </div>
            </div>
          </div>
        </div>

        {/* Bottom Links and Details */}
        <div
          ref={linksRef}
          className="grid grid-cols-1 md:grid-cols-12 gap-12 pt-12 border-t border-[#1c1c1e] opacity-0 text-sm"
        >
          {/* Column 1: Studio */}
          <div className="md:col-span-4 flex flex-col gap-3">
            <div className="text-xs uppercase tracking-widest font-mono text-[#8E8E93]">
              Lumer Labs
            </div>
            <div className="text-[#8E8E93] font-light leading-relaxed">
              Based globally, collaborating digitally.<br />
              Constructing portals worldwide.
            </div>
          </div>

          {/* Column 2: Nav */}
          <div className="md:col-span-3 flex flex-col gap-2">
            <div className="text-xs uppercase tracking-widest font-mono text-[#8E8E93] mb-1">
              Navigate
            </div>
            <a
              href="#about"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light"
            >
              Philosophy
            </a>
            <a
              href="#services"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light"
            >
              Capabilities
            </a>
            <a
              href="#contact"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light"
            >
              Inquiries
            </a>
          </div>

          {/* Column 3: Social */}
          <div className="md:col-span-3 flex flex-col gap-2">
            <div className="text-xs uppercase tracking-widest font-mono text-[#8E8E93] mb-1">
              Connect
            </div>
            <a
              href="https://x.com"
              target="_blank"
              rel="noreferrer"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light inline-flex items-center gap-1.5"
            >
              <span>Twitter</span>
              <ArrowUpRight className="w-3.5 h-3.5" />
            </a>
            <a
              href="https://linkedin.com"
              target="_blank"
              rel="noreferrer"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light inline-flex items-center gap-1.5"
            >
              <span>LinkedIn</span>
              <ArrowUpRight className="w-3.5 h-3.5" />
            </a>
            <a
              href="https://github.com"
              target="_blank"
              rel="noreferrer"
              className="text-[#8E8E93] hover:text-[#F5F5F7] transition-colors duration-300 font-light inline-flex items-center gap-1.5"
            >
              <span>GitHub</span>
              <ArrowUpRight className="w-3.5 h-3.5" />
            </a>
          </div>

          {/* Column 4: Top Action */}
          <div className="md:col-span-2 flex items-end md:justify-end">
            <button
              onClick={handleScrollToTop}
              className="text-[#8E8E93] hover:text-[#E5C158] font-mono text-xs tracking-wider uppercase border border-[#1c1c1e] hover:border-[#E5C158]/50 px-4 py-2.5 rounded-full transition-all duration-300 cursor-pointer"
              id="back-to-top"
            >
              Back to Top â†‘
            </button>
          </div>
        </div>

        {/* Footer Meta */}
        <div className="flex flex-col md:flex-row justify-between items-center gap-4 text-xs text-[#8E8E93]/60 font-mono tracking-wider pt-6">
          <div>Â© {new Date().getFullYear()} LUMER LABS. ALL RIGHTS RESERVED.</div>
          <div className="flex gap-4">
            <span>PRIVACY POLICY</span>
            <span>TERMS OF SERVICE</span>
          </div>
        </div>
      </div>
    </footer>
  );
}
