import React, { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import videoSrc from "../../149141-795734150_medium.mp4";

gsap.registerPlugin(ScrollTrigger);

export function Hero() {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const videoWrapperRef = useRef<HTMLDivElement>(null);
  const maskOverlayRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    const title = titleRef.current;
    const video = videoRef.current;
    const videoWrapper = videoWrapperRef.current;
    const maskOverlay = maskOverlayRef.current;
    const content = contentRef.current;

    if (!container || !title || !video || !videoWrapper || !maskOverlay || !content) return;

    // Ensure the video plays and is loop/muted
    video.muted = true;
    video.play().catch((err) => {
      console.log("Auto-play blocked or interrupted, attempting retry:", err);
      // Fallback interaction listener to play video on first click if blocked
      const playVideo = () => {
        video.play().catch(e => console.log(e));
        window.removeEventListener("click", playVideo);
      };
      window.addEventListener("click", playVideo);
    });

    // Detect screen size for responsive scale calculation
    const getTargetScale = () => {
      const width = window.innerWidth;
      if (width < 640) return 90;   // Mobile: smaller text, needs less zoom
      if (width < 1024) return 140; // Tablet
      return 220;                   // Desktop: needs massive scale to escape viewport
    };

    // Responsive border radius
    const getTargetBorderRadius = () => {
      return window.innerWidth < 768 ? "24px" : "40px";
    };

    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: container,
        start: "top top",
        end: "+=1800", // Scroll length for the cinematic zoom and shrink sequence
        scrub: 1,      // Smooth scrubbing linked to scroll speed
        pin: true,     // Pin the hero section during the transition
        anticipatePin: 1,
      },
    });

    // Step 1: Scale the text mask and reveal the video behind it
    tl.to(title, {
      scale: getTargetScale(),
      ease: "power2.inOut",
    })
    // Step 2: Gradually fade out the mask overlay to achieve full video reveal
    .to(maskOverlay, {
      opacity: 0,
      duration: 0.25,
      ease: "none",
    }, "-=0.2") // start fade slightly before zoom finishes
    // Step 3: Scale down the video container and round its corners to create breathing room
    .to(videoWrapper, {
      scale: 0.95,
      borderRadius: getTargetBorderRadius(),
      duration: 0.6,
      ease: "power2.inOut",
    })
    // Step 4: Fade in the overlay hero text content (studio tagline)
    .to(content, {
      opacity: 1,
      y: 0,
      duration: 0.4,
      ease: "power2.out",
    }, "-=0.2")
    // Step 5: Fade in the floating header navigation at the end of the reveal sequence
    .to("header", {
      opacity: 1,
      y: 0,
      pointerEvents: "auto",
      duration: 0.4,
      ease: "power2.out",
    }, "-=0.3");

    // Recalculate ScrollTrigger on window resize to keep scales responsive
    const handleResize = () => {
      ScrollTrigger.refresh();
    };
    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
      if (tl.scrollTrigger) tl.scrollTrigger.kill();
      tl.kill();
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className="relative w-full h-screen overflow-hidden bg-black select-none"
      id="hero"
    >
      {/* Video card wrapper that shrinks and rounds */}
      <div
        ref={videoWrapperRef}
        className="absolute inset-0 w-full h-full overflow-hidden origin-center bg-[#070708]"
      >
        <video
          ref={videoRef}
          src={videoSrc}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 w-full h-full object-cover"
        />

        {/* CSS Mask overlay. Black background, white text. Blend mode multiply creates the portal. */}
        <div
          ref={maskOverlayRef}
          className="absolute inset-0 bg-black text-white flex items-center justify-center mix-blend-multiply pointer-events-none select-none z-10"
        >
          <h1
            ref={titleRef}
            className="text-[12vw] font-primary font-black tracking-normal text-center uppercase origin-center select-none"
            style={{ willChange: "transform" }}
          >
            LUMERLABS
          </h1>
        </div>

        {/* Ambient shadow gradient at the bottom of the video for typography visibility */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent pointer-events-none z-20" />

        {/* Overlay Content: Taglines and Scroll indicator. Visible after shrink. */}
        <div
          ref={contentRef}
          className="absolute inset-x-0 bottom-12 px-8 md:px-16 flex flex-col md:flex-row md:justify-between md:items-end gap-6 opacity-0 translate-y-8 z-30 pointer-events-none"
        >
          <div className="max-w-md">
            <p className="text-[#8E8E93] text-xs uppercase tracking-widest font-semibold mb-2">
              Lumer Labs
            </p>
            <h2 className="text-2xl md:text-3xl font-primary font-light text-[#F5F5F7] leading-tight tracking-tight">
              Your Journey Beyond Ordinary Starts Here.
            </h2>
          </div>
          
          <div className="flex flex-col items-start md:items-end gap-2 text-xs text-[#8E8E93] tracking-wider uppercase font-semibold">
            <span>Scroll to Enter</span>
            <div className="w-6 h-10 border border-[#8E8E93]/30 rounded-full flex justify-center items-start p-1.5">
              {/* Animated mouse wheel dot */}
              <div className="w-1 h-2 bg-[#E5C158] rounded-full animate-bounce" />
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
