import React, { useRef, useEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { ArrowLeft, ArrowRight } from "lucide-react";

// Image Imports
import imgBranding from "../images/k5332ztmtcb91.jpg";
import imgDesigning from "../images/Celestial Spiral Art.png";
import imgVideography from "../images/2e45fc413fd255f1e218d9867814bfdb.jpg";
import imgAI from "../images/file_000000003bbc71f5ac267e055137f619.png";

gsap.registerPlugin(ScrollTrigger);

const services = [
  {
    title: "Branding",
    image: imgBranding,
    desc: ["Lorem ipsum", "dolor sit", "amet,", "consectetur", "adipiscing", "elit, sed do", "eiusmod", "tempor", "incididunt", "ut labore et", "dolore"],
  },
  {
    title: "Designing",
    image: imgDesigning,
    desc: ["Lorem ipsum", "dolor sit", "amet,", "consectetur", "adipiscing", "elit, sed do", "eiusmod", "tempor", "incididunt", "ut labore et", "dolore"],
  },
  {
    title: "Videography and\nEditing",
    image: imgVideography,
    desc: ["Lorem ipsum", "dolor sit", "amet,", "consectetur", "adipiscing", "elit, sed do", "eiusmod", "tempor", "incididunt", "ut labore et", "dolore"],
  },
  {
    title: "AI Automation",
    image: imgAI,
    desc: ["Lorem ipsum", "dolor sit", "amet,", "consectetur", "adipiscing", "elit, sed do", "eiusmod", "tempor", "incididunt", "ut labore et", "dolore"],
  },
];

export function Services() {
  const sectionRef = useRef<HTMLDivElement>(null);
  const headingRef = useRef<HTMLHeadingElement>(null);
  const sliderRef = useRef<HTMLDivElement>(null);
  const footerTextRef = useRef<HTMLParagraphElement>(null);
  const buttonsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const section = sectionRef.current;
    const heading = headingRef.current;
    const slider = sliderRef.current;
    const footerText = footerTextRef.current;
    const buttons = buttonsRef.current;

    if (!section || !heading || !slider || !footerText || !buttons) return;

    const headingWords = heading.querySelectorAll(".word-inner");
    const cards = slider.querySelectorAll(".service-card");

    const tl = gsap.timeline({
      scrollTrigger: {
        trigger: section,
        start: "top 75%",
        once: true,
      },
    });

    // 1. Heading slide-up staggered reveal
    tl.fromTo(
      headingWords,
      { y: "115%", rotate: 2 },
      {
        y: "0%",
        rotate: 0,
        duration: 1.0,
        ease: "power4.out",
        stagger: 0.08,
      }
    )
    // 2. Smooth slide-in of cards from the right
    .fromTo(
      cards,
      { x: 300, opacity: 0 },
      {
        x: 0,
        opacity: 1,
        duration: 1.4,
        ease: "power3.out",
        stagger: 0.15,
      },
      "-=0.6"
    )
    // 3. Staggered reveal of bottom elements
    .fromTo(
      [footerText, buttons],
      { y: 30, opacity: 0 },
      {
        y: 0,
        opacity: 1,
        duration: 1.0,
        ease: "power3.out",
        stagger: 0.1,
      },
      "-=0.8"
    );

    return () => {
      if (tl.scrollTrigger) tl.scrollTrigger.kill();
      tl.kill();
    };
  }, []);

  // Handle Horizontal Scroll buttons
  const handleScroll = (direction: "left" | "right") => {
    const container = sliderRef.current;
    if (!container) return;
    
    const cardWidth = container.querySelector(".service-card")?.clientWidth || 260;
    const scrollOffset = cardWidth + 24; // Card width + gap
    
    container.scrollBy({
      left: direction === "left" ? -scrollOffset : scrollOffset,
      behavior: "smooth",
    });
  };

  const titleText = "OUR SERVICES";

  return (
    <section
      ref={sectionRef}
      className="relative w-full h-screen bg-black text-[#F5F5F7] px-8 md:px-16 pt-24 pb-8 flex flex-col justify-between overflow-hidden border-t border-[#1c1c1e]/40 z-30"
      id="services"
    >
      <div className="w-full flex flex-col justify-between h-full flex-grow">
        
        {/* Title Block */}
        <div className="max-w-6xl mx-auto w-full pt-2">
          <h2
            ref={headingRef}
            className="text-5xl md:text-7xl lg:text-[5.5vw] font-primary font-semibold tracking-tight leading-none uppercase select-none text-left"
          >
            {titleText.split(" ").map((word, idx) => (
              <span key={idx} className="word-mask mr-[0.25em] py-[0.1em] -my-[0.1em]">
                <span className="word-inner inline-block transform origin-left">
                  {word}
                </span>
              </span>
            ))}
          </h2>
        </div>

        {/* Carousel Slider (Breaking out of right padding for edge bleed) */}
        <div className="w-full mr-[-2rem] md:mr-[-4rem] overflow-hidden">
          <div
            ref={sliderRef}
            className="flex gap-6 overflow-x-auto scrollbar-none pr-8 md:pr-16 py-2 select-none cursor-grab active:cursor-grabbing"
            style={{ scrollSnapType: "x mandatory" }}
          >
            {services.map((item, idx) => (
              <div
                key={idx}
                className="service-card service-card flex-shrink-0 w-[200px] md:w-[260px] scroll-snap-align-start flex flex-col opacity-0"
              >
                {/* Image Banner */}
                <div className="relative aspect-[4/5] rounded-[16px] overflow-hidden bg-[#070708]">
                  <img
                    src={item.image}
                    alt={item.title}
                    className="w-full h-full object-cover transition-transform duration-500 hover:scale-105 pointer-events-none"
                  />
                  
                  {/* Title overlay in monospace aligned bottom left */}
                  <div className="absolute bottom-4 left-4 right-4">
                    <h3 className="text-lg md:text-xl font-sans font-normal tracking-tight text-[#F5F5F7] text-left whitespace-pre-line leading-tight">
                      {item.title}
                    </h3>
                  </div>
                </div>

                {/* Vertical column description */}
                <div className="mt-4 text-left pl-1">
                  <div className="font-sans text-[10px] md:text-[11px] leading-tight text-[#8E8E93] uppercase font-light flex flex-col gap-0.5">
                    {item.desc.map((line, lIdx) => (
                      <span key={lIdx}>{line}</span>
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Metadata & Controls */}
        <div className="max-w-6xl mx-auto w-full flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mt-4">
          {/* Summary tagline */}
          <p
            ref={footerTextRef}
            className="text-sm md:text-base font-sans font-semibold max-w-xl text-left text-white leading-snug select-none opacity-0"
          >
            Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore
          </p>

          {/* Navigation Controls */}
          <div
            ref={buttonsRef}
            className="flex gap-4 self-end md:self-auto opacity-0"
          >
            <button
              onClick={() => handleScroll("left")}
              className="w-10 h-10 rounded-full border border-[#1c1c1e] hover:border-[#E5C158]/50 flex items-center justify-center text-[#8E8E93] hover:text-[#E5C158] hover:bg-[#121214]/50 transition-all duration-300 cursor-pointer"
              aria-label="Scroll left"
            >
              <ArrowLeft className="w-4 h-4" />
            </button>
            
            <button
              onClick={() => handleScroll("right")}
              className="w-10 h-10 rounded-full border border-[#1c1c1e] hover:border-[#E5C158]/50 flex items-center justify-center text-[#8E8E93] hover:text-[#E5C158] hover:bg-[#121214]/50 transition-all duration-300 cursor-pointer"
              aria-label="Scroll right"
            >
              <ArrowRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </section>
  );
}
