import React, { useState, useEffect } from "react";

export function Header() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 50) {
        setScrolled(true);
      } else {
        setScrolled(false);
      }
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const handleNavClick = (e: React.MouseEvent<HTMLAnchorElement>, id: string) => {
    e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <header
      className={`fixed top-0 left-0 w-full z-50 transition-all duration-500 py-6 px-8 md:px-16 mix-blend-difference ${
        scrolled ? "py-4" : ""
      }`}
      style={{ opacity: 0, transform: "translateY(-20px)", pointerEvents: "none" }}
    >
      <div className="max-w-6xl mx-auto w-full flex justify-between items-center">
        {/* Brand Logo */}
        <a
          href="#hero"
          onClick={(e) => handleNavClick(e, "hero")}
          className="text-xl font-primary font-semibold  text-[#F5F5F7] hover:text-[#E5C158] transition-colors duration-300"
          id="header-logo"
        >
          LumerLabs
        </a>

        {/* Desktop Navigation */}
        <nav className="hidden md:flex items-center gap-10">
          <a
            href="#about"
            onClick={(e) => handleNavClick(e, "about")}
            className="text-xs uppercase tracking-wider text-[#F5F5F7] hover:text-[#E5C158] transition-colors duration-300 font-medium"
          >
            Philosophy
          </a>
          <a
            href="#services"
            onClick={(e) => handleNavClick(e, "services")}
            className="text-xs uppercase tracking-wider text-[#F5F5F7] hover:text-[#E5C158] transition-colors duration-300 font-medium"
          >
            Capabilities
          </a>
          <a
            href="#contact"
            onClick={(e) => handleNavClick(e, "contact")}
            className="text-xs uppercase tracking-wider text-[#F5F5F7] hover:text-[#E5C158] transition-colors duration-300 font-medium"
          >
            Inquiries
          </a>
        </nav>

        {/* Contact CTA */}
        <div>
          <a
            href="#contact"
            onClick={(e) => handleNavClick(e, "contact")}
            className="text-xs uppercase tracking-widest font-mono text-black bg-[#F5F5F7] hover:bg-[#E5C158] px-5 py-2.5 rounded-full transition-all duration-300 font-bold"
            id="header-cta"
          >
            Align
          </a>
        </div>
      </div>
    </header>
  );
}
